let pageNavigationProgressTimer = 0;
function getPageNavigationProgressBar() {
let bar = document.getElementById("willpedia-page-progress");
if (bar) return bar;
bar = document.createElement("div");
bar.id = "willpedia-page-progress";
bar.setAttribute("aria-hidden", "true");
document.body.appendChild(bar);
return bar;
}
function markPageNavigationPending() {
try { sessionStorage.setItem(WILLPEDIA_NAV_PROGRESS_KEY, String(Date.now())); } catch (_) {}
}
function hasPendingPageNavigation() {
try {
const startedAt = Number(sessionStorage.getItem(WILLPEDIA_NAV_PROGRESS_KEY) || 0);
return startedAt > 0 && Date.now() - startedAt < 15000;
} catch (_) { return false; }
}
function clearPendingPageNavigation() {
try { sessionStorage.removeItem(WILLPEDIA_NAV_PROGRESS_KEY); } catch (_) {}
}
function startPageNavigationProgress() {
const bar = getPageNavigationProgressBar();
window.clearTimeout(pageNavigationProgressTimer);
bar.classList.remove("is-finishing", "is-waiting");
bar.classList.add("is-started");
pageNavigationProgressTimer = window.setTimeout(() => {
bar.classList.add("is-waiting");
}, 180);
}
function finishPageNavigationProgress() {
const bar = document.getElementById("willpedia-page-progress");
if (!bar) {
clearPendingPageNavigation();
return;
}
window.clearTimeout(pageNavigationProgressTimer);
bar.classList.remove("is-waiting");
bar.classList.add("is-finishing");
window.setTimeout(() => {
bar.classList.remove("is-started", "is-finishing");
clearPendingPageNavigation();
}, 220);
}
function resolveInternalUrl(target) {
return new URL(String(target || "index.html"), document.baseURI);
}
function navigateWithProgress(target, replace = false) {
const destination = resolveInternalUrl(target);
markPageNavigationPending();
startPageNavigationProgress();
if (replace) window.location.replace(destination.href);
else window.location.href = destination.href;
}
function setupPageNavigationProgress() {
if (hasPendingPageNavigation()) startPageNavigationProgress();
document.addEventListener("click", event => {
if (event.defaultPrevented || event.button !== 0 || event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) return;
const anchor = event.target.closest("a[href]");
if (!anchor || anchor.hasAttribute("download") || anchor.target === "_blank") return;
const rawHref = String(anchor.getAttribute("href") || "").trim();
if (!rawHref || rawHref.startsWith("#") || /^(?:javascript:|mailto:|tel:)/i.test(rawHref)) return;
let destination;
try { destination = new URL(anchor.href, document.baseURI); } catch (_) { return; }
if (destination.origin !== window.location.origin) return;
const onlyHashChanges = destination.pathname === window.location.pathname && destination.search === window.location.search && destination.hash !== window.location.hash;
if (onlyHashChanges) return;
markPageNavigationPending();
startPageNavigationProgress();
}, { capture: true });
window.addEventListener("pageshow", event => {
if (!event.persisted) return;
startPageNavigationProgress();
window.setTimeout(finishPageNavigationProgress, 90);
}, { passive: true });
}
