function convertPriceFromIDR(value) {
const numericValue = Number(value) || 0;
const config = CURRENCY_CONFIG[selectedCurrency] || CURRENCY_CONFIG.IDR;
return numericValue * config.rate;
}
function formatPrice(value) {
const convertedValue = convertPriceFromIDR(value);
if (selectedCurrency === "MYR") {
return `RM ${convertedValue.toLocaleString("en-MY", {
minimumFractionDigits: 2,
maximumFractionDigits: 2
})}`;
}
return `Rp ${Math.round(convertedValue).toLocaleString("id-ID")}`;
}
function getSelectedCurrencyConfig() {
return CURRENCY_CONFIG[selectedCurrency] || CURRENCY_CONFIG.IDR;
}
function formatCurrencyRateDate(rawDate) {
if (!rawDate)
return "";
const date = new Date(rawDate);
if (Number.isNaN(date.getTime()))
return String(rawDate);
return date.toLocaleDateString("id-ID", {
day: "2-digit",
month: "short",
year: "numeric"
});
}
function updateCurrencyRateStatus() {
const config = CURRENCY_CONFIG.MYR;
const rateMeta = document.getElementById("myr-rate-meta");
const sourceLink = document.getElementById("currency-rate-source-link");
const updatedAt = document.getElementById("currency-rate-updated-at");
const rateText = Number(config.rate).toLocaleString("en-MY", {
minimumFractionDigits: 6,
maximumFractionDigits: 8
});
const formattedDate = formatCurrencyRateDate(config.rateDate);
if (rateMeta) {
rateMeta.textContent = `1 IDR = ${rateText} MYR${formattedDate ? ` • ${formattedDate}` : ""}`;
}
if (sourceLink) {
sourceLink.textContent = config.sourceName ? `Sumber: ${config.sourceName}` : "Lihat sumber kurs";
if (config.sourceUrl)
sourceLink.href = config.sourceUrl;
}
if (updatedAt) {
updatedAt.textContent = formattedDate ? ` • diperbarui ${formattedDate}` : "";
}
}
