function enableGameTabsDrag() {
const scroller = document.querySelector('.game-tabs-scroll');
if (!scroller)
return;
let activePointerId = null;
let startX = 0;
let startY = 0;
let startScrollLeft = 0;
let isDragging = false;
let suppressNextClick = false;
scroller.addEventListener('pointerdown', (event) => {
if (event.pointerType !== 'mouse' || event.button !== 0)
return;
activePointerId = event.pointerId;
startX = event.clientX;
startY = event.clientY;
startScrollLeft = scroller.scrollLeft;
isDragging = false;
});
scroller.addEventListener('pointermove', (event) => {
if (event.pointerId !== activePointerId)
return;
const deltaX = event.clientX - startX;
const deltaY = event.clientY - startY;
if (!isDragging) {
if (Math.abs(deltaX) < 6 && Math.abs(deltaY) < 6)
return;
if (Math.abs(deltaY) > Math.abs(deltaX)) {
activePointerId = null;
return;
}
isDragging = true;
scroller.classList.add('dragging');
try {
scroller.setPointerCapture(event.pointerId);
}
catch (_) { }
}
scroller.scrollLeft = startScrollLeft - deltaX;
event.preventDefault();
});
const finishDrag = (event) => {
if (event.pointerId !== activePointerId)
return;
if (isDragging) {
suppressNextClick = true;
window.setTimeout(() => {
suppressNextClick = false;
}, 120);
}
scroller.classList.remove('dragging');
try {
if (scroller.hasPointerCapture(event.pointerId)) {
scroller.releasePointerCapture(event.pointerId);
}
}
catch (_) { }
activePointerId = null;
isDragging = false;
};
scroller.addEventListener('pointerup', finishDrag);
scroller.addEventListener('pointercancel', finishDrag);
scroller.addEventListener('click', (event) => {
if (!suppressNextClick)
return;
event.preventDefault();
event.stopPropagation();
}, true);
}
function setupGameTabsNavigation() {
const scroller = document.querySelector('.game-tabs-scroll');
const previousButton = document.getElementById('game-tabs-prev');
const nextButton = document.getElementById('game-tabs-next');
if (!scroller || !previousButton || !nextButton)
return;
let updateFrame = null;
const updateArrows = () => {
const maxScrollLeft = Math.max(0, scroller.scrollWidth - scroller.clientWidth);
const hasOverflow = maxScrollLeft > 4;
const isAtStart = scroller.scrollLeft <= 4;
const isAtEnd = scroller.scrollLeft >= maxScrollLeft - 4;
previousButton.classList.toggle('is-visible', hasOverflow && !isAtStart);
nextButton.classList.toggle('is-visible', hasOverflow && !isAtEnd);
};
const requestArrowUpdate = () => {
if (updateFrame)
cancelAnimationFrame(updateFrame);
updateFrame = requestAnimationFrame(updateArrows);
};
const getScrollDistance = () => Math.max(170, Math.round(scroller.clientWidth * 0.72));
previousButton.addEventListener('click', () => {
scroller.scrollBy({ left: -getScrollDistance(), behavior: 'smooth' });
});
nextButton.addEventListener('click', () => {
scroller.scrollBy({ left: getScrollDistance(), behavior: 'smooth' });
});
scroller.addEventListener('scroll', requestArrowUpdate, { passive: true });
window.addEventListener('resize', requestArrowUpdate, { passive: true });
if ('ResizeObserver' in window) {
const resizeObserver = new ResizeObserver(requestArrowUpdate);
resizeObserver.observe(scroller);
const track = scroller.querySelector('.game-tabs-track');
if (track)
resizeObserver.observe(track);
}
requestArrowUpdate();
}
const navbar = document.getElementById("navbar");
let navbarScrolled = null;
let navbarScrollFrame = 0;
function updateNavbarState() {
navbarScrollFrame = 0;
const nextState = window.scrollY > 80;
if (nextState === navbarScrolled)
return;
navbarScrolled = nextState;
navbar.classList.toggle("bg-slate-950/95", nextState);
navbar.classList.toggle("border-slate-800", nextState);
navbar.classList.toggle("shadow-xl", nextState);
navbar.classList.toggle("bg-white/5", !nextState);
navbar.classList.toggle("border-white/10", !nextState);
}
window.addEventListener("scroll", () => {
if (navbarScrollFrame)
return;
if (document.documentElement.classList.contains("is-low-power-device")) {
navbarScrollFrame = window.setTimeout(updateNavbarState, 80);
return;
}
navbarScrollFrame = requestAnimationFrame(updateNavbarState);
}, { passive: true });
function getGameKeyFromName(gameName) {
return GAME_NAME_TO_KEY[String(gameName || "").trim().toUpperCase()] || "";
}
function getGameNameFromKey(gameKey) {
return GAME_KEY_TO_NAME[String(gameKey || "").trim().toLowerCase()] || "";
}
function getRequestedGameRoute() {
const params = new URLSearchParams(window.location.search);
const bodyGameKey = String(document.body?.dataset?.game || "").trim().toLowerCase();
const pathSegments = window.location.pathname.split("/").filter(Boolean);
const pathGameKey = String(pathSegments[pathSegments.length - 1] || "").trim().toLowerCase();
const gameKey = bodyGameKey || (GAME_KEY_TO_NAME[pathGameKey] ? pathGameKey : "") || String(params.get("game") || "").trim().toLowerCase();
return {
gameKey,
productId: String(params.get("product") || "").trim()
};
}
function buildGamePageUrl(gameName, productId = "") {
const gameKey = getGameKeyFromName(gameName);
if (!gameKey) return "index.html#game-menu-view";
const params = new URLSearchParams();
if (productId) params.set("product", String(productId));
const query = params.toString();
return `${gameKey}/${query ? `?${query}` : ""}`;
}
function getStaticProductDataPath(params) {
const action = String(params?.action || "").trim().toLowerCase();
if (action === "popular") return STATIC_PRODUCT_DATA_FILES.popular;
if (action === "products") {
const gameKey = String(params?.game || "").trim().toLowerCase();
return STATIC_PRODUCT_DATA_FILES.products[gameKey] || "";
}
return "";
}
function normalizeStaticRatingSummary(rawSummary) {
const total = Math.max(0, Number(rawSummary?.total ?? rawSummary?.jumlah_ulasan ?? 0) || 0);
const average = Math.max(0, Math.min(5, Number(rawSummary?.average ?? rawSummary?.rata_rata ?? 0) || 0));
return { average, total, comments: [] };
}
function cacheStaticRatingSummary(gameKeyOrName, rawSummary) {
const normalizedKey = String(gameKeyOrName || "").trim().toLowerCase();
const gameName = GAME_KEY_TO_NAME[normalizedKey] || String(gameKeyOrName || "").trim().toUpperCase();
if (!GAME_NAME_TO_KEY[gameName]) return;
gameReviewSummaryCache.set(gameName, normalizeStaticRatingSummary(rawSummary));
}
function ingestStaticRatingPayload(payload, params) {
if (!payload || typeof payload !== "object") return;
const action = String(params?.action || "").trim().toLowerCase();
if (action === "products") {
const gameKey = String(params?.game || payload.game || "").trim().toLowerCase();
if (gameKey && payload.rating) cacheStaticRatingSummary(gameKey, payload.rating);
return;
}
if (action === "popular" && payload.ratings && typeof payload.ratings === "object") {
Object.entries(payload.ratings).forEach(([gameKey, summary]) => cacheStaticRatingSummary(gameKey, summary));
}
}
function scheduleIdleTask(callback, timeout = 900) {
if ("requestIdleCallback" in window) {
window.requestIdleCallback(() => callback(), { timeout });
return;
}
window.setTimeout(callback, Math.min(timeout, 350));
}
function normalizePopularPayload(rawPayload) {
if (Array.isArray(rawPayload)) {
return { success: true, products: rawPayload, ratings: {} };
}
if (!rawPayload || typeof rawPayload !== "object" || rawPayload.success === false || !Array.isArray(rawPayload.products)) {
return null;
}
return rawPayload;
}
function readEmbeddedPopularPayload() {
const element = document.getElementById(HOME_POPULAR_EMBED_ID);
if (!element) return null;
try {
return normalizePopularPayload(JSON.parse(element.textContent || "null"));
} catch (error) {
console.warn("Data paket terlaris tertanam tidak valid:", error);
return null;
}
}
function readCachedHomePopularPayload() {
try {
const cached = JSON.parse(localStorage.getItem(HOME_POPULAR_CACHE_KEY) || "null");
if (!cached || Date.now() - Number(cached.savedAt || 0) > HOME_POPULAR_CACHE_TTL) return null;
return normalizePopularPayload(cached.payload);
} catch (_) {
return null;
}
}
function saveCachedHomePopularPayload(payload) {
try {
localStorage.setItem(HOME_POPULAR_CACHE_KEY, JSON.stringify({ savedAt: Date.now(), payload }));
} catch (_) {}
}
function applyHomePopularPayload(rawPayload, options = {}) {
const payload = normalizePopularPayload(rawPayload);
if (!payload || !payload.products.length) return false;
ingestStaticRatingPayload(payload, { action: "popular" });
const products = payload.products.map(normalizeProductRecord);
const changed = getProductDataSignature(homePopularProducts) !== getProductDataSignature(products);
homePopularProducts = products;
allProducts = products;
mobileProductVisibleCount = MOBILE_PRODUCT_BATCH_SIZE;
if (changed || options.forceRender) {
renderWeeklyPopularPackages();
renderMobileSearchItems("");
}
if (options.cache !== false) saveCachedHomePopularPayload(payload);
scheduleAllGameRatingsLoad();
return true;
}
async function fetchStaticPayloadObject(params, cacheMode = "no-cache") {
const path = getStaticProductDataPath(params);
if (!path) throw new Error("Data statis tidak tersedia untuk endpoint ini");
const url = new URL(path, document.baseURI);
const response = await fetch(url.toString(), { cache: cacheMode });
if (!response.ok) throw new Error(`Static JSON HTTP ${response.status}`);
const payload = await response.json();
if (Array.isArray(payload)) return { success: true, products: payload };
if (payload && payload.success !== false && Array.isArray(payload.products)) return payload;
throw new Error(payload?.message || "Static JSON belum tersinkron");
}
async function fetchStaticProductPayload(params) {
const payload = await fetchStaticPayloadObject(params, "no-cache");
ingestStaticRatingPayload(payload, params);
return payload.products;
}
async function fetchProductPayload(params) {
const staticPath = getStaticProductDataPath(params);
if (staticPath) {
try {
return await fetchStaticProductPayload(params);
} catch (staticError) {
console.warn("Static JSON belum siap, menggunakan Apps Script:", staticError);
}
}
const url = new URL(API_URL);
Object.entries(params || {}).forEach(([key, value]) => {
if (value !== undefined && value !== null && String(value) !== "") url.searchParams.set(key, String(value));
});
const response = await fetch(url.toString(), { cache: "no-store" });
if (!response.ok) throw new Error(`HTTP ${response.status}`);
const payload = await response.json();
if (Array.isArray(payload)) return payload;
if (payload && payload.success !== false && Array.isArray(payload.products)) return payload.products;
throw new Error(payload?.message || "Format data produk tidak valid");
}
