function collectAllGameComments(results, limit = 20) {
const queues = results
.filter(result => result.success)
.map(result => Array.isArray(result.summary?.comments)
? [...result.summary.comments]
: [])
.filter(queue => queue.length);
const comments = [];
const seen = new Set();
let queueIndex = 0;
while (queues.length && comments.length < limit) {
const currentIndex = queueIndex % queues.length;
const queue = queues[currentIndex];
const comment = queue.shift();
if (!queue.length)
queues.splice(currentIndex, 1);
else
queueIndex += 1;
if (!comment)
continue;
const key = [
comment.__gameName || "",
comment.Nama || "",
comment.Komentar || "",
comment.Tanggal || ""
].join("|").toLowerCase();
if (seen.has(key))
continue;
seen.add(key);
comments.push(comment);
}
return comments;
}
