async function loadHomeCommentsOnDemand() {
if (homeCommentsLoadPromise) return homeCommentsLoadPromise;
setAllGameCommentsLoading();
homeCommentsLoadPromise = (async () => {
try {
let comments;
try {
comments = await fetchStaticHomeReviews();
} catch (staticError) {
console.warn("Komentar JSON statis belum tersedia, memakai sumber langsung:", staticError);
const live = await fetchLiveAllGameReviews();
comments = live.comments;
live.summaries.forEach((summary, gameName) => gameReviewSummaryCache.set(gameName, summary));
}
const results = groupStaticReviewsByGame(comments);
homeCommentsLoaded = true;
allGameRatingsResultsCache = results;
renderAllGameComments(results, getSelectedCommentGameName());
} catch (error) {
console.warn("Komentar belum dapat dimuat:", error);
homeCommentsLoaded = false;
renderHomeCommentsLoadButton("Komentar belum dapat dimuat. Silakan coba lagi.");
} finally {
homeCommentsLoadPromise = null;
}
})();
return homeCommentsLoadPromise;
}
async function loadAllGameRatings() {
const gameNames = getAvailableGameNames();
const scoreElement = document.getElementById("all-game-rating-overall-score");
const metaElement = document.getElementById("all-game-rating-overall-meta");
const renderToken = ++allGameRatingsRenderToken;
renderAllGameRatingsShell(gameNames);
if (!gameNames.length) {
allGameRatingsResultsCache = [];
if (scoreElement) scoreElement.textContent = "0.0";
if (metaElement) metaElement.textContent = "Belum ada game Ready";
prepareHomeCommentsOnDemand();
return;
}
if (scoreElement) scoreElement.textContent = "—";
if (metaElement) metaElement.textContent = "Memuat ringkasan rating...";
gameNames.forEach(gameName => renderAllGameRatingCardState(gameName, null, "loading"));
const results = await Promise.all(gameNames.map(async gameName => {
try {
let summary = gameReviewSummaryCache.get(gameName);
if (!summary || !gameReviewSummaryResolved.has(gameName)) {
summary = await fetchGameRatingSummaryOnly(gameName);
}
return { gameName, summary, success: true };
} catch (error) {
console.warn(`Gagal mengambil rating ${gameName}:`, error);
return { gameName, summary: null, success: false };
}
}));
if (renderToken !== allGameRatingsRenderToken) return;
allGameRatingsResultsCache = results;
let weightedRatingTotal = 0;
let reviewTotal = 0;
let errorTotal = 0;
results.forEach(result => {
if (!result.success) {
errorTotal += 1;
renderAllGameRatingCardState(result.gameName, null, "error");
return;
}
renderAllGameRatingCardState(result.gameName, result.summary);
const total = Number(result.summary?.total || 0);
const average = Number(result.summary?.average || 0);
weightedRatingTotal += average * total;
reviewTotal += total;
});
const overallAverage = reviewTotal ? weightedRatingTotal / reviewTotal : 0;
if (scoreElement) scoreElement.textContent = reviewTotal ? overallAverage.toFixed(1) : "0.0";
if (metaElement) {
if (errorTotal === gameNames.length) metaElement.textContent = "Rating belum dapat dimuat";
else if (errorTotal > 0) metaElement.textContent = `${reviewTotal.toLocaleString("id-ID")} ulasan • sebagian game gagal dimuat`;
else if (reviewTotal > 0) metaElement.textContent = `${reviewTotal.toLocaleString("id-ID")} ulasan`;
else metaElement.textContent = "Belum ada ulasan";
}
if (document.body?.dataset?.page === "ratings") {
homeCommentsPanelOpen = true;
updateHomeCommentsToggle();
await loadHomeCommentsOnDemand();
} else {
prepareHomeCommentsOnDemand();
}
}
