async function submitInlineReview(event) {
event.preventDefault();
const productId = currentReviewProductId;
const name = document.getElementById("inline-review-name")?.value.trim() || "";
const comment = document.getElementById("inline-review-comment")?.value.trim() || "";
const submitButton = document.getElementById("inline-review-submit");
if (!productId) {
showInlineReviewNotice("Pilih game terlebih dahulu.", "error");
return;
}
if (name.length < 2) {
showInlineReviewNotice("Nama minimal 2 karakter.", "error");
return;
}
if (selectedInlineReviewRating < 1 || selectedInlineReviewRating > 5) {
showInlineReviewNotice("Pilih rating 1 sampai 5 bintang.", "error");
return;
}
if (comment.length < 5) {
showInlineReviewNotice("Komentar minimal 5 karakter.", "error");
return;
}
const body = new URLSearchParams({
action: "add_comment",
id_produk: productId,
nama: name,
rating: String(selectedInlineReviewRating),
komentar: comment
});
if (submitButton) {
submitButton.disabled = true;
submitButton.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i><span>Mengirim...</span>';
}
try {
const response = await fetch(API_URL, {
method: "POST",
body
});
if (!response.ok)
throw new Error(`HTTP ${response.status}`);
const result = await response.json();
if (!result.success)
throw new Error(result.message || "Ulasan gagal dikirim.");
showInlineReviewNotice(result.message || "Ulasan berhasil dikirim dan menunggu persetujuan admin.");
reviewCache.delete(productId);
const submittedGameName = getProductById(productId)?.Game || currentGameFilter;
gameReviewSummaryCache.delete(submittedGameName);
gameReviewSummaryResolved.delete(submittedGameName);
staticReviewsBundlePromise = null;
resetInlineReviewForm();
showInlineReviewNotice(result.message || "Ulasan berhasil dikirim dan menunggu persetujuan admin.");
window.setTimeout(() => {
loadProductReviews(productId, true);
}, 250);
}
catch (error) {
console.error("Gagal mengirim ulasan:", error);
showInlineReviewNotice("Ulasan gagal dikirim. Pastikan koneksi dan Apps Script aktif.", "error");
}
finally {
if (submitButton) {
submitButton.disabled = false;
submitButton.innerHTML = '<i class="fa-solid fa-paper-plane"></i><span>Kirim Ulasan</span>';
}
}
}
function scrollBackToPackages() {
document.getElementById("product-container")?.scrollIntoView({
behavior: "smooth",
block: "start"
});
window.setTimeout(requestReviewBackButtonUpdate, 450);
}
let reviewBackButtonScrollFrame = 0;
let reviewBackButtonMeasureFrame = 0;
let reviewBackButtonTriggerY = Number.POSITIVE_INFINITY;
let reviewBackButtonResizeObserver = null;
function measureReviewBackButtonTrigger() {
reviewBackButtonMeasureFrame = 0;
const productContainer = document.getElementById("product-container");
const reviewSection = document.getElementById("inline-review-section") || document.getElementById("game-reviews-section");
if (!productContainer) {
reviewBackButtonTriggerY = Number.POSITIVE_INFINITY;
return;
}
const productTop = productContainer.getBoundingClientRect().top + window.scrollY;
const fallbackTrigger = productTop + Math.max(window.innerHeight * 1.35, 900);
const reviewTop = reviewSection
? reviewSection.getBoundingClientRect().top + window.scrollY
: fallbackTrigger;
reviewBackButtonTriggerY = Math.max(
Math.min(reviewTop - window.innerHeight * 0.7, fallbackTrigger),
700
);
updateReviewBackButtonVisibility();
}
function scheduleReviewBackButtonMeasure() {
if (document.body?.dataset?.page !== "game" || reviewBackButtonMeasureFrame) return;
reviewBackButtonMeasureFrame = window.requestAnimationFrame(measureReviewBackButtonTrigger);
}
function updateReviewBackButtonVisibility() {
reviewBackButtonScrollFrame = 0;
const backButton = document.getElementById("review-back-button");
const detailView = document.getElementById("game-detail-view");
if (!backButton || !detailView)
return;
if (window.matchMedia("(min-width: 1024px)").matches) {
backButton.classList.add("hidden");
return;
}
const detailIsVisible = currentGameFilter !== "Semua" &&
!detailView.classList.contains("hidden");
const shouldShow = detailIsVisible && window.scrollY > reviewBackButtonTriggerY;
backButton.classList.toggle("hidden", !shouldShow);
}
function requestReviewBackButtonUpdate() {
if (reviewBackButtonScrollFrame)
return;
reviewBackButtonScrollFrame = window.requestAnimationFrame(updateReviewBackButtonVisibility);
}
function setupInlineReviewSection() {
const form = document.getElementById("inline-review-form");
const comment = document.getElementById("inline-review-comment");
document.querySelectorAll("[data-inline-rating]").forEach(button => {
button.addEventListener("click", () => {
selectInlineReviewRating(button.dataset.inlineRating);
});
});
comment?.addEventListener("input", () => {
const count = document.getElementById("inline-review-character-count");
if (count)
count.textContent = `${comment.value.length}/300`;
});
form?.addEventListener("submit", submitInlineReview);
if (document.body?.dataset?.page === "game") {
window.addEventListener("scroll", requestReviewBackButtonUpdate, { passive: true });
window.addEventListener("resize", scheduleReviewBackButtonMeasure, { passive: true });
const productContainer = document.getElementById("product-container");
const reviewSection = document.getElementById("inline-review-section") || document.getElementById("game-reviews-section");
if ("ResizeObserver" in window && productContainer) {
reviewBackButtonResizeObserver?.disconnect();
reviewBackButtonResizeObserver = new ResizeObserver(scheduleReviewBackButtonMeasure);
reviewBackButtonResizeObserver.observe(productContainer);
if (reviewSection) reviewBackButtonResizeObserver.observe(reviewSection);
}
scheduleReviewBackButtonMeasure();
}
}
